const resolvers = {
  Query: {
    user: (_parent, { id }, ctx) => ctx.db.users.findById(id),
  },
  User: {
    // parent is the User object returned above
    orders: (user, { first, after }, ctx) =>
      ctx.db.orders.page({ userId: user.id, first, after }),
  },
  Order: {
    // total has no resolver -> default resolver returns order.total
    lineItems: (order, _args, ctx) =>
      ctx.loaders.lineItemsByOrder.load(order.id),
  },
  Mutation: {
    placeOrder: async (_p, { input }, ctx) => {
      if (!ctx.user) throw new GraphQLError('Unauthenticated', {
        extensions: { code: 'UNAUTHENTICATED' },
      });
      return ctx.orderService.place(ctx.user.id, input);
    },
  },
};

