import DataLoader from 'dataloader';

export function makeLoaders(db) {
  return {
    lineItemsByOrder: new DataLoader<string, LineItem[]>(async (orderIds) => {
      const rows = await db.query(
        'SELECT * FROM line_items WHERE order_id = ANY($1)',
        [orderIds],
      );
      const byOrder = new Map<string, LineItem[]>();
      for (const r of rows) {
        (byOrder.get(r.order_id) ?? byOrder.set(r.order_id, []).get(r.order_id)!).push(r);
      }
      // CRITICAL: return one entry per key, in the SAME ORDER as orderIds
      return orderIds.map((id) => byOrder.get(id) ?? []);
    }),
  };
}

type OrderConnection {
  edges: [OrderEdge!]!
  pageInfo: PageInfo!
  totalCount: Int
}

type OrderEdge {
  cursor: String!
  node: Order!
}

type PageInfo {
  hasNextPage: Boolean!
  hasPreviousPage: Boolean!
  startCursor: String
  endCursor: String
}

