const productsById = new DataLoader<string, Product>(async (ids) => {
  const rows = await db.query(
    'SELECT * FROM products WHERE id = ANY($1)', [ids]);
  const map = new Map(rows.map((p) => [p.id, p]));
  return ids.map((id) => map.get(id) ?? null); // preserve order + length
});

