import DataLoader from 'dataloader';

interface User { id: string; displayName: string; }

// 1) Per-request loader factory
export function makeLoaders(db: Db) {
  return {
    authorById: new DataLoader<string, User | null>(async (ids) => {
      const rows: User[] = await db.query(
        'SELECT id, display_name AS "displayName" FROM users WHERE id = ANY($1)',
        [ids as string[]],
      );
      const byId = new Map(rows.map((u) => [u.id, u]));
      // CRITICAL: same order, same length as input ids; null for misses
      return ids.map((id) => byId.get(id) ?? null);
    }),
  };
}

// 2) Build context per request
export function buildContext(req: Request, db: Db) {
  return { db, loaders: makeLoaders(db), user: authenticate(req) };
}

// 3) Resolvers use the loader instead of querying directly
export const resolvers = {
  Query: {
    posts: (_p: unknown, _a: unknown, ctx: Ctx) => ctx.db.query('SELECT * FROM posts LIMIT 100'),
  },
  Post: {
    // 100 posts -> 100 load() calls -> 1 batched query
    author: (post: { authorId: string }, _a: unknown, ctx: Ctx) =>
      ctx.loaders.authorById.load(post.authorId),
  },
};

function encodeCursor(placedAt: Date, id: string): string {
  return Buffer.from(`${placedAt.toISOString()}:${id}`).toString('base64');
}

function decodeCursor(c: string): { placedAt: string; id: string } {
  const raw = Buffer.from(c, 'base64').toString('utf8');
  const idx = raw.indexOf(':');
  return { placedAt: raw.slice(0, idx), id: raw.slice(idx + 1) };
}

export async function ordersConnection(
  userId: string,
  first: number,
  after: string | null,
  db: Db,
) {
  const limit = Math.min(first, 100); // cap page size
  const params: any[] = [userId];
  let keyset = '';
  if (after) {
    const { placedAt, id } = decodeCursor(after);
    params.push(placedAt, id);
    keyset = `AND (placed_at, id) < ($2, $3)`;
  }
  params.push(limit + 1); // fetch one extra to detect next page

  const rows = await db.query(
    `SELECT id, placed_at AS "placedAt" FROM orders
     WHERE user_id = $1 ${keyset}
     ORDER BY placed_at DESC, id DESC
     LIMIT $${params.length}`,
    params,
  );

  const hasNextPage = rows.length > limit;
  const page = hasNextPage ? rows.slice(0, limit) : rows;
  const edges = page.map((o: any) => ({
    cursor: encodeCursor(o.placedAt, o.id),
    node: o,
  }));

  return {
    edges,
    pageInfo: {
      hasNextPage,
      hasPreviousPage: Boolean(after),
      startCursor: edges[0]?.cursor ?? null,
      endCursor: edges[edges.length - 1]?.cursor ?? null,
    },
  };
}
